Find the bug(s) in the following code and explain the fix:

```javascript
function processApiResponse(jsonString) {
  const data = JSON.parse(jsonString)

  // Calculate time since creation
  const now = new Date()
  const created = data.created  // "2024-01-15T10:30:00.000Z"
  const age = now.getTime() - created.getTime()
  console.log(`Record age: ${age}ms`)

  // Find most recent update
  const updates = data.updates  // [{"date": "2024-02-01T...", "note": "..."}, ...]
  const sorted = updates.sort((a, b) => b.date.getTime() - a.date.getTime())
  console.log(`Latest update: ${sorted[0].date.toISOString()}`)

  return {
    age,
    latestUpdate: sorted[0]
  }
}

const json = JSON.stringify({
  created: new Date('2024-01-15T10:30:00Z'),
  updates: [
    { date: new Date('2024-02-01T08:00:00Z'), note: 'first update' },
    { date: new Date('2024-03-15T14:30:00Z'), note: 'second update' }
  ]
})

processApiResponse(json)
// TypeError: created.getTime is not a function
```
